codeExamples.code:
let home = {
  motherName: "mary",
  fatherName: "tom",
  dogs: 3,
  isWakeUp: false
};

let home = { motherName: "mary", dogs: 3 };
console.log(home.motherName);
console.log(home.dogs);

let colors = ["red", "blue"];
console.log(colors[0]);

let person = { name: "tom", age: 25 };
console.log(person.name);

let person = { name: "Wayne", age: 20 };
console.log(person["name"]);

let key = "age";
console.log(person[key]);
console.log(person.key);

let dog = {
  name: "Lucky",
  bark: function() {
    console.log("汪汪！");
  }
};
dog.bark();

