  motherName: "mary",
  fatherName: "tom",
  dogs: 3
};
console.log(home.fatherName);

let person = { name: "alice", age: 20 };
let myAge = person.age;
console.log(myAge);

let person = { name: "Wayne", age: 20 };
let key = "name";
console.log(person[key]);
console.log(person.key);

let cat = {
  name: "mimi",
  meow: function() {
    console.log("喵喵！");
  }
};
cat.meow();

let scores = {
  math: 90,
  english: 85,
  science: 78
};
let subjects = ["math", "english", "science"];
console.log(scores[subjects[0]]);
console.log(scores[subjects[2]]);

